import React, { useEffect, useState } from "react";
import { Table, Select, Spin } from "antd"; // Added Spin component for loading state
import { BiEdit } from "react-icons/bi";
import { AiFillDelete } from "react-icons/ai";
import { useDispatch, useSelector } from "react-redux";
import {
  deleteAProduct,
  getEachMechantProduct,
  updateProductStatus,
} from "../../features/product/productSlice";
import { Link, useLocation } from "react-router-dom";
import { delImg } from "../../features/upload/uploadSlice";
import CustomModal from "../../components/CustomModal";
import Loading from "../../utils/Loading";

const { Option } = Select;

const EachMerchantProductlist = () => {
  const [open, setOpen] = useState(false);
  const [productId, setProductId] = useState("");

  const location = useLocation();
  const role = location.pathname.split("/")[1];

  const dispatch = useDispatch();

  // Retrieve merchant ID from local storage
  useEffect(() => {
    const user = JSON.parse(localStorage.getItem("user"));
    if (user && user._id) {
      console.log(user._id);
      dispatch(getEachMechantProduct(user._id));
    }
  }, [dispatch]);

  const { productsMerchant, loading } = useSelector((state) => state.product);
  const user = useSelector((state) => state.auth.user);
  const data = productsMerchant?.data || []; // Added fallback to avoid destructuring errors
  console.log("🚀 ~ EachMerchantProductlist ~ data:", data);
  const showModal = (id) => {
    setOpen(true);
    setProductId(id);
  };

  const hideModal = () => {
    setOpen(false);
  };

  const data1 = data.map((product, index) => ({
    key: index + 1,
    _id: product._id,
    title: product.title,
    photo: product.colors[0]?.images[0]?.secure_url,
    brand: product.brand,
    category: product.category,
    quantity: product.quantity,
    price: `${product.price}`,
    availability: product.status,
    action: (
      <>
        {(role === "merchant" || role === "admin") && (
          <>
            <Link
              to={`/${role}/product/${product._id}`}
              className="fs-3 text-success"
            >
              <BiEdit />
            </Link>
            <button
              className="ms-3 fs-3 text-danger bg-transparent border-0"
              onClick={() => showModal(product._id)}
            >
              <AiFillDelete />
            </button>
          </>
        )}
      </>
    ),
  }));

  const columns = [
    {
      title: "SNo",
      dataIndex: "key",
    },
    {
      title: "Title",
      dataIndex: "title",
      sorter: (a, b) => a.title.length - b.title.length,
      render: (text, record) => (
        <Link to={`${record._id}`} className="text-blue-500 hover:underline">
          {text}
        </Link>
      ),
    },
    {
      title: "Photo",
      dataIndex: "photo",
      render: (text, record) => (
        <Link to={`${record._id}`} className="text-blue-500 hover:underline">
          <img
            src={record.photo}
            alt={record.title}
            style={{ width: "50px", height: "50px" }}
          />
        </Link>
      ),
    },
    {
      title: "Brand",
      dataIndex: "brand",
      sorter: (a, b) => a.brand.length - b.brand.length,
      render: (text, record) => (
        <Link to={`${record._id}`} className="text-blue-500 hover:underline">
          {text}
        </Link>
      ),
    },
    {
      title: "Category",
      dataIndex: "category",
      sorter: (a, b) => a.category.length - b.category.length,
      render: (text, record) => (
        <Link to={`${record._id}`} className="text-blue-500 hover:underline">
          {text}
        </Link>
      ),
    },
    {
      title: "StockQuantity",
      dataIndex: "quantity",
      render: (text, record) => (
        <Link to={`${record._id}`} className="text-blue-500 hover:underline">
          {text}
        </Link>
      ),
    },
    {
      title: "Price",
      dataIndex: "price",
      sorter: (a, b) => a.price - b.price,
      render: (text, record) => (
        <Link to={`${record._id}`} className="text-blue-500 hover:underline">
          {text}
        </Link>
      ),
    },

    {
      title: "Action",
      dataIndex: "action",
    },
  ];

  const deleteProduct = (id) => {
    dispatch(deleteAProduct({ productId: id, userId: user?._id }));
    dispatch(delImg(id));

    setOpen(false);

    // Retrieve merchantId from localStorage and refresh product list
    const user = JSON.parse(localStorage.getItem("user"));
    if (user && user._id) {
      dispatch(getEachMechantProduct(user._id)); // Refresh the product list after deletion
    }
  };

  if (loading)
    return (
      <p>
        <Loading />
      </p>
    );
  return (
    <div>
      <h3 className="mb-4 title">Products</h3>
      <div>
        {loading ? (
          <Spin size="large" /> // Show loading spinner while fetching data
        ) : (
          <Table columns={columns} dataSource={data1} />
        )}
      </div>
      <CustomModal
        hideModal={hideModal}
        open={open}
        performAction={() => {
          deleteProduct(productId);
        }}
        title="Are you sure you want to delete this Product?"
      />
    </div>
  );
};

export default EachMerchantProductlist;
